  const [risk, setRisk] = useState(null);
  const [err, setErr] = useState("");
  const [dots, setDots] = useState("");
  const [vis, setVis] = useState(false);

  useEffect(() => { setTimeout(() => setVis(true), 200); }, []);
  useEffect(() => { if (step !== "analyzing") return; const iv = setInterval(() => setDots(d => d.length >= 3 ? "" : d + "."), 400); return () => clearInterval(iv); }, [step]);
  
  const API_BASE = import.meta.env.VITE_API_BASE || "http://localhost:3001";

  const go = () => { const t = addr.trim(); if (!t) return; if (/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(t)) { setChain(CHAINS.find(c => c.id === "solana")); setStep("paste"); } else setStep("chain"); };
  const API_BASE =
  import.meta.env.VITE_API_BASE ||
  "http://localhost:3000";

const run = async () => {
  if (!data.trim()) return;

  setStep("analyzing");
  setResult("");
  setErr("");
  setRisk(null);

  try {
    const response = await fetch(
      `${API_BASE}/api/analyze`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          address: addr,
          chain: chain.name,
          explorer: chain.explorer,
          walletData: data,
        }),
      }
    );

    const result = await response.json();

    if (!response.ok) {
      throw new Error(
        result.error?.message ||
          result.error ||
          "Analysis failed"
      );
    }

    const text =
      result.content
        ?.map((b) => b.text || "")
        .join("\n") || "No response";

    setResult(text);

    const match = text.match(
      /Overall Risk:\s*(\d+)\/100/i
    );

    if (match) {
      setRisk(parseInt(match[1]));
    }

    setStep("result");
  } catch (error) {
    console.error(error);

    setErr(error.message);

    setStep("paste");
  }
};

